// ═══════════════════════════════════════════════════════
// Step 1: Konfiguration - Generische Parameter
// Hier werden alle variablen Parameter definiert,
// die den Flow fuer verschiedene Mitbewerber anpassbar machen.
// ═══════════════════════════════════════════════════════

// --- ANPASSEN: Eigene Firma ---
const OWN_COMPANY_NAME = 'HanseMerkur';
const OWN_COMPANY_SHORT = 'HMR';
const OWN_PRODUCT_NAME = 'Seminar-Ruecktrittsversicherung';

// --- ANPASSEN: Mitbewerber ---
const COMPETITOR_NAME = 'ERGO Reiseversicherung';
const COMPETITOR_SHORT = 'ERV';
const COMPETITOR_PRODUCT_NAME = 'Seminar-Versicherung';

// --- ANPASSEN: RAG Collection ID des Mitbewerbers ---
const COMPETITOR_RAG_COLLECTION = '32c26a09-6c8c-449c-a060-1146f20c0322';

// --- ANPASSEN: API Einstellungen ---
const API_BASE_URL = 'https://aihubtest.hanse-merkur.de';
const RAG_ENDPOINT = '/api/v1/retrieval/query/collection';
const LLM_ENDPOINT = '/api/chat/completions';
const LLM_MODEL = 'qwen3:30b-a3b-instruct-2507-q8_0';
const RAG_TOP_K = 5;

return {
  config: {
    ownCompanyName: OWN_COMPANY_NAME,
    ownCompanyShort: OWN_COMPANY_SHORT,
    ownProductName: OWN_PRODUCT_NAME,
    competitorName: COMPETITOR_NAME,
    competitorShort: COMPETITOR_SHORT,
    competitorProductName: COMPETITOR_PRODUCT_NAME,
    competitorRagCollection: COMPETITOR_RAG_COLLECTION,
    apiBaseUrl: API_BASE_URL,
    ragEndpoint: RAG_ENDPOINT,
    llmEndpoint: LLM_ENDPOINT,
    llmModel: LLM_MODEL,
    ragTopK: RAG_TOP_K
  }
};

// ═══════════════════════════════════════════════════════
// Step 2: Eigene Hard Facts + RAG-Queries
// Eigene Daten = hardcoded (z.B. aus Excel/AVB)
// Mitbewerber-Daten = werden per RAG abgefragt
// benchmark_competitor = optionaler Referenzwert zum Abgleich
//
// ANPASSEN: Fakten fuer das jeweilige Produkt eintragen.
// Die Struktur bleibt generisch:
//   - own_data: eigene Leistung/Regelung
//   - rag_query: Frage an die Mitbewerber-AVB
//   - benchmark_competitor: optionaler Referenzwert
// ═══════════════════════════════════════════════════════

const config = $('01 - Config Parameters').first().json.config;

const facts = [
  {
    id: 1,
    kategorie: 'Produktuebersicht',
    aspekt: 'Produktname und Versicherungssparten',
    own_data: 'Seminar-Ruecktrittsversicherung. Sparte: Reise-Ruecktritt. Geltungsbereich: Europa.',
    rag_query: `Wie heisst das Produkt der ${config.competitorName} fuer Seminare? Welche Sparten sind enthalten? Welcher raeumliche Geltungsbereich gilt?`,
    benchmark_competitor: 'Seminar-Versicherung. Sparten: Reise-Ruecktritt und Reiseabbruch. Geltungsbereich: weltweit.'
  },
  {
    id: 2,
    kategorie: 'Produktuebersicht',
    aspekt: 'AVB-Version und Selbstbehalt',
    own_data: 'AVB: VB-RS 2021 (T-Seminar-D). Selbstbehalt: 20% bei ambulant behandelten Erkrankungen, mind. 25 EUR je versicherter Person.',
    rag_query: `Welche Versicherungsbedingungen (AVB) gelten fuer die ${config.competitorName} Seminar-Versicherung? Gibt es einen Selbstbehalt oder eine Selbstbeteiligung?`,
    benchmark_competitor: 'VB-ERV/Seminar 2017. Kein Selbstbehalt.'
  },
  {
    id: 3,
    kategorie: 'Versicherte Leistungen - Ruecktritt',
    aspekt: 'Stornokosten bei Nichtantritt des Seminars',
    own_data: 'Uebernahme der Stornokosten fuer das nicht angetretene Seminar.',
    rag_query: `Was erstattet die ${config.competitorName} Seminar-Versicherung bei Stornierung bzw. Ruecktritt vom Seminar? Werden auch Stornokosten fuer Seminarreihen und zusaetzliche Reiseleistungen uebernommen?`,
    benchmark_competitor: 'Uebernahme der Stornokosten fuer das Seminar bzw. fuer nicht besuchte Teilveranstaltungen der Seminarreihe. Uebernahme der Stornokosten fuer mitversicherte Reiseleistungen.'
  },
  {
    id: 4,
    kategorie: 'Versicherte Leistungen - Ruecktritt',
    aspekt: 'Verspaeteter Seminarantritt',
    own_data: 'Erstattung der Hinreise-Mehrkosten bis maximal zur Hoehe der Stornokosten, die bei einer Stornierung anfallen.',
    rag_query: `Was leistet die ${config.competitorName} Seminar-Versicherung bei verspaetem Seminarantritt? Werden Mehrkosten der Anreise und nicht genutzte Seminarleistungen erstattet?`,
    benchmark_competitor: 'Erstattung der Mehrkosten der Anreise. Erstattung der nicht genutzten Seminar- und Reiseleistungen abzueglich der Anreisekosten.'
  },
  {
    id: 5,
    kategorie: 'Versicherte Leistungen - Ruecktritt',
    aspekt: 'Verspaetung oeffentliches Verkehrsmittel (mehr als 2 Stunden)',
    own_data: 'Erstattung der Hinreise-Mehrkosten bis maximal zur Hoehe der Stornokosten.',
    rag_query: `Was erstattet die ${config.competitorName} Seminar-Versicherung bei Verspaetung eines oeffentlichen Verkehrsmittels um mehr als zwei Stunden? Gibt es einen Verspaetungsschutz mit Betraegen fuer Anreise-Mehrkosten, Verpflegung und Unterkunft?`,
    benchmark_competitor: 'Erstattung der Anreise-Mehrkosten bis 500 EUR. Kosten fuer Verpflegung sowie Unterkunft bis 100 EUR.'
  },
  {
    id: 6,
    kategorie: 'Versicherte Leistungen - Ruecktritt',
    aspekt: 'Panne oder Unfall des eigenen Kraftfahrzeugs',
    own_data: 'Nicht versichert. Nur wenn dadurch das versicherte Verkehrsmittel versaeumt wird: Erstattung der Hinreise-Mehrkosten bis maximal zur Hoehe der Stornokosten.',
    rag_query: `Was leistet die ${config.competitorName} Seminar-Versicherung bei Panne oder Unfall des eigenen Kraftfahrzeugs? Werden Kosten fuer nicht genutzte Leistungen, zusaetzliche Reisekosten oder ein Mietfahrzeug erstattet?`,
    benchmark_competitor: 'Erstattung der Kosten fuer nicht in Anspruch genommene Seminar- und Reiseleistungen oder zusaetzliche Reisekosten bis 500 EUR. Kostenerstattung fuer ein Mietfahrzeug bis 1.000 EUR.'
  },
  {
    id: 7,
    kategorie: 'Versicherte Leistungen - Ruecktritt',
    aspekt: 'Umbuchung des Seminars',
    own_data: 'Erstattung der Umbuchungskosten bis maximal zur Hoehe der Stornokosten.',
    rag_query: `Sind Umbuchungsgebuehren bei der ${config.competitorName} Seminar-Versicherung versichert? Bis zu welcher Hoehe werden Umbuchungsgebuehren erstattet?`,
    benchmark_competitor: 'Erstattung der Umbuchungsgebuehren, max. bis zur Hoehe der Stornokosten.'
  },
  {
    id: 8,
    kategorie: 'Reiseabbruch',
    aspekt: 'Abbruch des Seminars',
    own_data: 'Nicht versichert.',
    rag_query: `Was leistet die ${config.competitorName} Seminar-Versicherung bei Abbruch des Seminars? Werden anteilige Preise fuer nicht genutzte Leistungen und zusaetzliche Rueckreisekosten erstattet?`,
    benchmark_competitor: 'Erstattung des anteiligen Preises fuer nicht genutzte Seminar- und Reiseleistungen vor Ort. Erstattung der zusaetzlichen Rueckreisekosten.'
  },
  {
    id: 9,
    kategorie: 'Reiseabbruch',
    aspekt: 'Verspaetete Rueckreise vom Seminar',
    own_data: 'Nicht versichert.',
    rag_query: `Hilft die ${config.competitorName} Seminar-Versicherung bei verspaeteter Rueckreise vom Seminar? Wird die Rueckreise organisiert oder ein Darlehen fuer Mehrkosten gewaehrt?`,
    benchmark_competitor: 'Organisation der Rueckreise und Darlehen fuer Rueckreise-Mehrkosten.'
  },
  {
    id: 10,
    kategorie: 'Reiseabbruch',
    aspekt: 'Verlaengerter Aufenthalt wegen stationaerer Behandlung',
    own_data: 'Nicht versichert.',
    rag_query: `Erstattet die ${config.competitorName} Seminar-Versicherung zusaetzliche Unterkunftskosten bei verlaengertem Aufenthalt wegen stationaerer Behandlung? Bis zu welchem Betrag?`,
    benchmark_competitor: 'Erstattung zusaetzlicher Unterkunftskosten bis zu 1.500 EUR je Versicherungsfall.'
  },
  {
    id: 11,
    kategorie: 'Reiseabbruch',
    aspekt: 'Verlaengerter Aufenthalt wegen ambulanter Behandlung',
    own_data: 'Nicht versichert.',
    rag_query: `Erstattet die ${config.competitorName} Seminar-Versicherung zusaetzliche Unterkunftskosten bei verlaengertem Aufenthalt wegen ambulanter Behandlung? Bis zu welchem Betrag?`,
    benchmark_competitor: 'Erstattung zusaetzlicher Unterkunftskosten bis zu 750 EUR je Versicherungsfall.'
  },
  {
    id: 12,
    kategorie: 'Reiseabbruch',
    aspekt: 'Verlaengerter Aufenthalt wegen Feuer oder Elementarereignissen',
    own_data: 'Nicht versichert.',
    rag_query: `Was leistet die ${config.competitorName} Seminar-Versicherung bei Feuer oder Elementarereignissen am Seminarort? Werden Mehrkosten fuer verlaengerten Aufenthalt und ausserplanmaessige Rueckreise erstattet?`,
    benchmark_competitor: 'Mehrkosten fuer verlaengerten Aufenthalt. Mehrkosten fuer ausserplanmaessige Rueckreise.'
  },
  {
    id: 13,
    kategorie: 'Versicherte Ereignisse',
    aspekt: 'Nichtversetzung als Schueler oder Student',
    own_data: 'Versichert.',
    rag_query: `Ist Nichtversetzung eines Schuelers oder Studenten ein versichertes Ereignis bei der ${config.competitorName} Seminar-Versicherung? Welche Pruefungsereignisse sind versichert?`,
    benchmark_competitor: 'Nicht versichert.'
  },
  {
    id: 14,
    kategorie: 'Versicherte Ereignisse',
    aspekt: 'Panne oder Unfall des Kraftfahrzeuges als Ruecktrittsgrund',
    own_data: 'Nicht direkt versichert. Nur indirekt wenn dadurch das versicherte Verkehrsmittel versaeumt wird.',
    rag_query: `Ist Panne oder Unfall des eigenen Kraftfahrzeugs ein versichertes Ereignis bei der ${config.competitorName} Seminar-Versicherung das zum Ruecktritt berechtigt?`,
    benchmark_competitor: 'Versichert.'
  },
  {
    id: 15,
    kategorie: 'Versicherte Ereignisse',
    aspekt: 'Erkrankung, Unfall oder Tod eines Hundes oder einer Katze',
    own_data: 'Versichert.',
    rag_query: `Ist die Erkrankung, der Unfall oder Tod eines Hundes oder einer Katze ein versichertes Ereignis bei der ${config.competitorName} Seminar-Versicherung?`,
    benchmark_competitor: 'Nicht versichert.'
  },
  {
    id: 16,
    kategorie: 'Versicherte Ereignisse',
    aspekt: 'Feuer oder Elementarereignisse am Seminarort',
    own_data: 'Nicht versichert.',
    rag_query: `Sind Feuer oder Elementarereignisse am Seminarort versicherte Ereignisse bei der ${config.competitorName} Seminar-Versicherung? Was zaehlt als Elementarereignis?`,
    benchmark_competitor: 'Versichert.'
  },
  {
    id: 17,
    kategorie: 'Versicherte Ereignisse',
    aspekt: 'Absage durch den Veranstalter',
    own_data: 'Nicht versichert.',
    rag_query: `Ist die Absage des Seminars durch den Veranstalter ein versichertes Ereignis bei der ${config.competitorName} Seminar-Versicherung? Was wird in diesem Fall erstattet?`,
    benchmark_competitor: 'Versichert.'
  },
  {
    id: 18,
    kategorie: 'Weiteres',
    aspekt: 'Mitversicherung zusaetzlich gebuchter Reiseleistungen',
    own_data: 'Nicht versichert. Die Versicherungssumme sichert den Seminarpreis ab. Weitere Reiseleistungen muessen separat versichert werden.',
    rag_query: `Sind zusaetzlich gebuchte Reiseleistungen wie Anreise, Rueckreise und Unterkunft bei der ${config.competitorName} Seminar-Versicherung mitversichert? Welche zeitlichen Voraussetzungen gelten?`,
    benchmark_competitor: 'Versichert, vorausgesetzt sie liegen innerhalb 48 Stunden vor Beginn bis 48 Stunden nach Ende des Seminars.'
  },
  {
    id: 19,
    kategorie: 'Weiteres',
    aspekt: 'Maximal versicherbarer Zeitraum und Seminarreihen',
    own_data: '1 Seminarreise, unabhaengig von der Seminardauer. Bei Seminarreihen muss jedes Modul separat abgeschlossen werden.',
    rag_query: `Wie lange ist der maximal versicherbare Zeitraum bei der ${config.competitorName} Seminar-Versicherung? Koennen Seminarreihen mit mehreren Teilveranstaltungen versichert werden? Bis zu welcher Dauer?`,
    benchmark_competitor: '1 Seminarreise oder -reihe, unabhaengig von der Seminardauer, auch fuer Seminarreihen bis 2 Jahre.'
  },
  {
    id: 20,
    kategorie: 'Weiteres',
    aspekt: 'Abschlussfristen',
    own_data: 'Abschluss bis 30 Tage vor Reisebeginn oder spaetestens bis zum 3. Werktag nach der Reisebuchung.',
    rag_query: `Welche Abschlussfristen gelten fuer die ${config.competitorName} Seminar-Versicherung? Bis wann muss der Versicherungsvertrag abgeschlossen werden?`,
    benchmark_competitor: 'Am Buchungstag, spaetestens 30 Tage vor planmaessigem Antritt. Bei Buchung innerhalb von 30 Tagen vor Antritt nur am Buchungstag, spaetestens innerhalb der naechsten 3 Werktage.'
  }
];

return facts.map(f => ({ json: { ...f, config: config } }));

// ═══════════════════════════════════════════════════════
// Step 4: Build RAG Request gegen Mitbewerber Collection
// Generisch: Verwendet die Collection-ID aus der Config
// ═══════════════════════════════════════════════════════
const fact = $input.item.json;
const config = fact.config;

return {
  ...fact,
  retrievalRequestBody: JSON.stringify({
    collection_names: [config.competitorRagCollection],
    query: fact.rag_query,
    k: config.ragTopK
  })
};

// ═══════════════════════════════════════════════════════
// Step 6: Parse RAG + Build LLM Comparison Request
// Generisch: Verwendet Config fuer Firmennamen und Modell
// Das LLM extrahiert Mitbewerber-Infos AUS DEM RAG
// ═══════════════════════════════════════════════════════
const ragResp = $input.item.json;
const fact = $('04 - Build RAG Request').item.json;
const config = fact.config;

const docs = ragResp.documents?.[0] || [];
const metas = ragResp.metadatas?.[0] || [];
const dists = ragResp.distances?.[0] || [];

const contextChunks = docs.map((text, i) => {
  const meta = metas[i] || {};
  const source = (meta.name || meta.source || 'Unbekannt')
    .replace(/\.md\.txt$|\.txt$|\.md$/gi, '').replace(/_/g, ' ').trim();
  const dist = dists[i] || 'N/A';
  return '### Chunk ' + (i+1) + ' (Quelle: ' + source + ', Distance: ' + (typeof dist === 'number' ? dist.toFixed(3) : dist) + ')\n' + text;
}).join('\n\n');

const systemPrompt = `Du bist ein Versicherungsexperte, der AVB (Allgemeine Versicherungsbedingungen) analysiert und vergleicht.

Deine Aufgabe: Analysiere die bereitgestellten ${config.competitorName} AVB-Dokumente zu einem bestimmten Aspekt und vergleiche das Ergebnis mit der ${config.ownCompanyName} ${config.ownProductName}.

## WICHTIGE REGELN:
1. Extrahiere die ${config.competitorShort}-Informationen AUSSCHLIEssLICH aus den bereitgestellten RAG-Dokumenten
2. Wenn die Dokumente KEINE Information zu diesem Aspekt enthalten, schreibe klar: "In den vorliegenden ${config.competitorShort} AVB wurde hierzu keine Regelung gefunden."
3. ERFINDE KEINE Informationen - nur was in den Dokumenten steht
4. Sei praezise: Nenne konkrete Betraege, Prozentsaetze, Bedingungen, Paragraphen
5. Zitiere relevante Passagen aus den Dokumenten
6. Bewerte am Ende: Welcher Anbieter bietet hier den besseren Schutz? (${config.ownCompanyShort} besser / ${config.competitorShort} besser / gleichwertig / nicht vergleichbar)
7. Antworte auf Deutsch in strukturierter Form

## Bereitgestellte ${config.competitorShort} AVB-Dokumente:
` + contextChunks;

const userPrompt = `Analysiere und vergleiche folgenden Aspekt:

**Kategorie:** ${fact.kategorie}
**Aspekt:** ${fact.aspekt}

**${config.ownCompanyName} (${config.ownCompanyShort}) Regelung:**
${fact.own_data}

**Frage an die ${config.competitorShort} AVB:**
${fact.rag_query}

Bitte:
1. Was genau sagen die ${config.competitorShort} AVB-Dokumente zu diesem Aspekt? Zitiere relevante Stellen.
2. Fasse die ${config.competitorShort}-Regelung in 1-3 Saetzen zusammen
3. Vergleiche mit der ${config.ownCompanyShort}-Regelung: Was sind die konkreten Unterschiede?
4. Bewertung: Wer bietet den besseren Schutz fuer diesen Aspekt?`;

return {
  ...fact,
  ragContext: contextChunks,
  ragChunkCount: docs.length,
  ragDistances: dists.filter(d => typeof d === 'number').map(d => d.toFixed(3)),
  requestBody: JSON.stringify({
    model: config.llmModel,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ],
    temperature: 0.2,
    max_tokens: 1200,
    stream: false
  })
};

// ═══════════════════════════════════════════════════════
// Step 8: Parse LLM Result + Benchmark-Abgleich
// Generisch: Verwendet config fuer Firmennamen
// ═══════════════════════════════════════════════════════
const llmResp = $input.item.json;
const fact = $('06 - Parse RAG + Build LLM Request').item.json;
const config = fact.config;

let answer = (llmResp.choices?.[0]?.message?.content || '')
  .replace(/<think>[\s\S]*?<\/think>/g, '')
  .trim();

// Bewertung extrahieren (letzter Satz oder Zeile mit 'besser'/'gleichwertig')
let bewertung = 'nicht ermittelt';
const bewertungMatch = answer.match(new RegExp(
  `(${config.ownCompanyShort}\\s+besser|${config.competitorShort}\\s+besser|gleichwertig|nicht vergleichbar)`,
  'i'
));
if (bewertungMatch) {
  bewertung = bewertungMatch[1];
}

return {
  id: fact.id,
  kategorie: fact.kategorie,
  aspekt: fact.aspekt,
  own_data: fact.own_data,
  benchmark_competitor: fact.benchmark_competitor,
  vergleich_aus_rag: answer,
  bewertung: bewertung,
  ragChunkCount: fact.ragChunkCount,
  ragDistances: fact.ragDistances,
  tokens: llmResp.usage?.total_tokens || 0,
  config: config
};

// ═══════════════════════════════════════════════════════
// Step 9: Build Final Synthesis
// Sammelt ALLE Einzelvergleiche und baut den
// finalen LLM-Request fuer die Gesamtgegenueberstellung
// Generisch: Verwendet Config fuer Firmennamen
// ═══════════════════════════════════════════════════════
const allItems = $input.all();
const results = allItems.map(item => item.json);
const config = results[0]?.config || {};

const comparisonSections = results.map(r => {
  return '## ' + r.id + '. ' + r.kategorie + ' - ' + r.aspekt + '\n\n' +
    '**' + config.ownCompanyName + ' (' + config.ownCompanyShort + '):** ' + r.own_data + '\n\n' +
    '**' + config.competitorShort + ' laut RAG-Analyse:**\n' + r.vergleich_aus_rag + '\n\n' +
    '**Benchmark (Excel-Referenz):** ' + r.benchmark_competitor + '\n' +
    '*RAG Chunks: ' + r.ragChunkCount + ' | Distances: ' + (r.ragDistances || []).join(', ') + '*\n';
}).join('\n---\n\n');

const systemPrompt = `Du bist ein Versicherungsexperte der ${config.ownCompanyName}. ` +
  `Du erstellst eine Executive Summary eines AVB-Vergleichs zwischen der ` +
  `${config.ownCompanyName} ${config.ownProductName} und der ${config.competitorName} ${config.competitorProductName}.\n\n` +
  `Die Einzelvergleiche basieren auf einer RAG-Analyse der ${config.competitorShort} AVB-Dokumente. ` +
  'Zusaetzlich ist ein Benchmark-Wert aus einer manuellen Excel-Analyse angegeben.\n\n' +
  '## Aufgabe:\n' +
  'Erstelle basierend auf den Einzelvergleichen eine strukturierte Gegenueberstellung mit:\n\n' +
  `1. **Executive Summary** (3-5 Saetze Gesamtbewertung)\n` +
  `2. **Vorteile ${config.ownCompanyName}** (Bullet-Liste: wo ${config.ownCompanyShort} besser ist, mit konkreten Details)\n` +
  `3. **Vorteile ${config.competitorName}** (Bullet-Liste: wo ${config.competitorShort} besser ist, mit konkreten Details)\n` +
  '4. **Gleichwertige Leistungen** (wo beide aehnlich sind)\n' +
  '5. **Kritische Unterschiede** (die wichtigsten Differenzen fuer die Kundenberatung)\n' +
  `6. **Handlungsempfehlung fuer Produktmanagement** (wo sollte ${config.ownCompanyShort} nachbessern?)\n` +
  '7. **RAG-Qualitaetsbericht** (Vergleiche die RAG-Ergebnisse mit den Benchmark-Werten: ' +
  'Wo stimmen sie ueberein? Wo gibt es Abweichungen? ' +
  'Welche Aspekte konnten nicht aus den AVB ermittelt werden?)\n\n' +
  'Formatiere als Markdown. Sei praezise und faktenbasiert. ' +
  'Unterscheide klar zwischen Fakten aus den AVB und eigenen Bewertungen.';

const userPrompt = 'Hier sind die ' + results.length + ' Einzelvergleiche ' +
  '(jeweils mit RAG-Ergebnis und Excel-Benchmark):\n\n' +
  comparisonSections + '\n\n' +
  'Erstelle bitte die Gesamtgegenueberstellung mit RAG-Qualitaetsbericht.';

return [{
  json: {
    allResults: results,
    resultCount: results.length,
    config: config,
    requestBody: JSON.stringify({
      model: config.llmModel,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.3,
      max_tokens: 4000,
      stream: false
    })
  }
}];

// ═══════════════════════════════════════════════════════
// Step 11: Parse Final Synthesis + Build Output
// ═══════════════════════════════════════════════════════
const llmResp = $input.item.json;
const synthData = $('09 - Build Synthese-Request').item.json;
const config = synthData.config;

let synthesis = (llmResp.choices?.[0]?.message?.content || '')
  .replace(/<think>[\s\S]*?<\/think>/g, '')
  .trim();

const usage = llmResp.usage || {};

return {
  gesamtvergleich: synthesis,
  einzelvergleiche: synthData.allResults,
  anzahlFakten: synthData.resultCount,
  model: llmResp.model || config.llmModel,
  config: config,
  usage: {
    promptTokens: usage.prompt_tokens || 0,
    completionTokens: usage.completion_tokens || 0,
    totalTokens: usage.total_tokens || 0
  },
  timestamp: new Date().toISOString(),
  status: 'completed'
};

// ═══════════════════════════════════════════════════════
// Step 12: Report-Tabelle erstellen
// Erzeugt eine strukturierte Tabelle mit allen Ergebnissen
// fuer die Anzeige in n8n und fuer den Export
// ═══════════════════════════════════════════════════════
const data = $input.item.json;
const config = data.config;
const einzelvergleiche = data.einzelvergleiche || [];

// --- Tabellen-Zeilen als Array of Objects (fuer n8n Table View) ---
const reportTable = einzelvergleiche.map(e => ({
  Nr: e.id,
  Kategorie: e.kategorie,
  Aspekt: e.aspekt,
  [config.ownCompanyShort]: e.own_data,
  [`${config.competitorShort} (RAG)`]: (e.vergleich_aus_rag || '').substring(0, 300) + ((e.vergleich_aus_rag || '').length > 300 ? '...' : ''),
  [`${config.competitorShort} (Benchmark)`]: e.benchmark_competitor,
  Bewertung: e.bewertung || 'nicht ermittelt',
  RAG_Chunks: e.ragChunkCount,
  RAG_Distances: (e.ragDistances || []).join(', '),
  Tokens: e.tokens
}));

// --- Zusammenfassung ---
const ownBetter = einzelvergleiche.filter(e => (e.bewertung || '').toLowerCase().includes(config.ownCompanyShort.toLowerCase() + ' besser')).length;
const compBetter = einzelvergleiche.filter(e => (e.bewertung || '').toLowerCase().includes(config.competitorShort.toLowerCase() + ' besser')).length;
const equal = einzelvergleiche.filter(e => (e.bewertung || '').toLowerCase().includes('gleichwertig')).length;
const unclear = einzelvergleiche.length - ownBetter - compBetter - equal;

return {
  reportTable: reportTable,
  summary: {
    totalFacts: einzelvergleiche.length,
    ownBetter: ownBetter,
    competitorBetter: compBetter,
    equal: equal,
    unclear: unclear,
    ownCompany: config.ownCompanyName,
    competitor: config.competitorName
  },
  gesamtvergleich: data.gesamtvergleich,
  config: config,
  meta: {
    model: data.model,
    usage: data.usage,
    timestamp: data.timestamp,
    status: data.status
  }
};

// ═══════════════════════════════════════════════════════
// Step 13: Final Report Output
// Erzeugt den vollstaendigen Report als Markdown
// mit Tabelle und Zusammenfassung
// ═══════════════════════════════════════════════════════
const data = $input.item.json;
const config = data.config;
const reportTable = data.reportTable || [];
const summary = data.summary || {};

// --- Markdown Report Table ---
const tableHeader = `| Nr | Kategorie | Aspekt | ${config.ownCompanyShort} | ${config.competitorShort} (RAG) | ${config.competitorShort} (Benchmark) | Bewertung |`;
const tableSeparator = '|-----|-----------|--------|' + '-'.repeat(config.ownCompanyShort.length + 2) + '|' + '-'.repeat(config.competitorShort.length + 8) + '|' + '-'.repeat(config.competitorShort.length + 14) + '|-----------|';
const tableRows = reportTable.map(r =>
  `| ${r.Nr} | ${r.Kategorie} | ${r.Aspekt} | ${r[config.ownCompanyShort] || ''} | ${r[config.competitorShort + ' (RAG)'] || ''} | ${r[config.competitorShort + ' (Benchmark)'] || ''} | ${r.Bewertung} |`
).join('\n');

const summaryBlock = `## Zusammenfassung\n\n` +
  `| Metrik | Wert |\n` +
  `|--------|------|\n` +
  `| Verglichene Fakten | ${summary.totalFacts} |\n` +
  `| ${config.ownCompanyShort} besser | ${summary.ownBetter} |\n` +
  `| ${config.competitorShort} besser | ${summary.competitorBetter} |\n` +
  `| Gleichwertig | ${summary.equal} |\n` +
  `| Nicht eindeutig | ${summary.unclear} |\n`;

const fullReport = `# AVB-Vergleich: ${config.ownCompanyName} vs. ${config.competitorName}\n\n` +
  `**Erstellt:** ${data.meta.timestamp}\n` +
  `**Modell:** ${data.meta.model}\n` +
  `**Verglichene Fakten:** ${summary.totalFacts}\n` +
  `**Gesamt-Tokens Synthese:** ${data.meta.usage.totalTokens}\n` +
  `**Mitbewerber-Datenquelle:** RAG Collection ${config.competitorRagCollection}\n\n` +
  '---\n\n' +
  summaryBlock + '\n\n' +
  '---\n\n' +
  '# Executive Summary und Gegenueberstellung\n\n' +
  data.gesamtvergleich + '\n\n' +
  '---\n\n' +
  '# Vergleichstabelle\n\n' +
  tableHeader + '\n' + tableSeparator + '\n' + tableRows + '\n';

// Return both the structured table (for n8n table view) and the full report
return {
  report: fullReport,
  reportTable: reportTable,
  summary: summary,
  gesamtvergleich: data.gesamtvergleich,
  meta: data.meta
};
